import { scope } from "arktype";

try {
  const types = scope({
    "db.User": {
      id: "string.uuid",
      name: "string >= 1 <= 50",
      orgId: "string.uuid"
    }
  }).export();
  console.log("Success:", types.db.User({ id: "123e4567-e89b-12d3-a456-426614174000", name: "Alice", orgId: "123e4567-e89b-12d3-a456-426614174000" }));
} catch (e) {
  console.error(e);
}

import { scope } from "arktype";

try {
  const types = scope({
    "db.User": {
      id: "string.uuid",
      name: "1<=string<=50",
      orgId: "string.uuid"
    }
  }).export();
  console.log("Keys:", Object.keys(types));
  console.log("db:", types.db);
} catch (e) {
  console.error(e);
}

import { scope } from "arktype";

try {
  const s = scope({
    "db.User": {
      id: "string.uuid",
      name: "1<=string<=50",
      orgId: "string.uuid"
    }
  });
  console.log("Scope properties:", Object.keys(s));
  const types = s.export();
  console.log("Exported properties:", Object.keys(types));
} catch (e) {
  console.error(e);
}

