import { Scope } from "arktype";

try {
  const types = Scope.module({
    "db.User": {
      id: "string.uuid",
      name: "string >= 1 <= 50",
      orgId: "string.uuid"
    }
  });
  console.log("types.db:", types.db);
} catch (e) {
  console.error(e);
}

