import { scope } from "arktype";

const s = scope({
  "db.User": { id: "string.uuid", name: "string >= 1 <= 50", orgId: "string.uuid" },
  "db.Org": { id: "string.uuid", name: "string >= 1 <= 100" }
});

const types = s.export();
console.log(Object.keys(types));
console.log(types.db);

import { Module, scope } from "arktype";

try {
  const dbModule = Module({
    User: { id: "string.uuid", name: "string >= 1 <= 50", orgId: "string.uuid" }
  });
  console.log("dbModule:", dbModule);
} catch (e) {
  console.error(e);
}

import { Module, scope } from "arktype";

try {
  const dbModule = new Module({
    User: { id: "string.uuid", name: "string >= 1 <= 50", orgId: "string.uuid" }
  });
  const types = scope({ db: dbModule }).export();
  console.log("types.db:", types.db);
  console.log("types.db.User:", types.db.User);
} catch (e) {
  console.error(e);
}

