import { scope } from "arktype";

const types = scope({
  "db.User": {
    id: "string.uuid",
    name: "string >= 1 <= 50",
    orgId: "string.uuid"
  },
  "db.Org": {
    id: "string.uuid",
    name: "string >= 1 <= 100"
  },
  "api.CreateUserRequest": {
    user: "db.User",
    token: "string >= 32 <= 256"
  },
  "api.CreateOrgRequest": {
    org: "db.Org",
    adminUserId: "string.uuid"
  }
}).export();

export const module = {
  db: {
    User: types["db.User"],
    Org: types["db.Org"]
  },
  api: {
    CreateUserRequest: types["api.CreateUserRequest"],
    CreateOrgRequest: types["api.CreateOrgRequest"]
  }
};

import { module } from "./src/schema.js";

async function main() {
  const buffers: Buffer[] = [];
  for await (const chunk of process.stdin) {
    buffers.push(chunk);
  }
  const input = Buffer.concat(buffers).toString("utf-8");

  let parsed: any;
  try {
    parsed = JSON.parse(input);
  } catch (e: any) {
    console.log(`INVALID: Malformed JSON (${e.message})`);
    process.exit(0);
  }

  if (!parsed || typeof parsed !== "object") {
    console.log("INVALID: Expected a JSON object");
    process.exit(0);
  }

  const kind = parsed.kind;
  const payload = parsed.payload;

  if (!kind || typeof kind !== "string") {
    console.log("INVALID: Missing or invalid 'kind' field");
    process.exit(0);
  }

  let schema;
  if (kind === "createUser") {
    schema = module.api.CreateUserRequest;
  } else if (kind === "createOrg") {
    schema = module.api.CreateOrgRequest;
  } else {
    console.log(`INVALID: Unknown kind '${kind}'`);
    process.exit(0);
  }

  const out = schema(payload);
  if (out instanceof Error) {
    console.log(`INVALID: ${out.message}`);
  } else {
    console.log("VALID");
    console.log(JSON.stringify(out));
  }
}

main().catch(e => {
  console.log(`INVALID: Internal error - ${e.message}`);
  process.exit(0);
});

