const types = scope({
  "db.User": { id: "string.uuid", name: "string >= 1 <= 50", orgId: "string.uuid" }
}).export();
try {
  console.log(types.db);
  console.log(types.db.User);
} catch(e) {
  console.log(e.message);
}
